// Module Worker context \u2014 top-level await supported

// \u2500\u2500\u2500 State \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500
let pyodide = null;
let loading = false;
let loadError = null;

// \u2500\u2500\u2500 Helpers \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500
function sendMsg(msg) {
  self.postMessage(msg);
}

function ensureParentDirs(FS, path) {
  const dir = path.lastIndexOf("/");
  if (dir > 0) {
    const parent = path.slice(0, dir);
    try { FS.mkdirTree(parent); } catch {}
  }
}

function walkMemfs(FS, dir, depth, visited) {
  if (depth === undefined) depth = 0;
  if (visited === undefined) visited = new Set();
  const results = [];
  if (depth > 100 || visited.has(dir)) return results;
  visited.add(dir);
  let entries;
  try { entries = FS.readdir(dir); } catch { return results; }
  for (const entry of entries) {
    if (entry === "." || entry === "..") continue;
    const fullPath = dir === "/" ? "/" + entry : dir + "/" + entry;
    try {
      const stat = FS.stat(fullPath);
      if (stat.isDirectory) {
        results.push.apply(results, walkMemfs(FS, fullPath, depth + 1, visited));
      } else {
        results.push(fullPath);
      }
    } catch {}
  }
  return results;
}

// \u2500\u2500\u2500 Init \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500
async function initPyodide(requestId) {
  if (pyodide) {
    sendMsg({ type: "ready", requestId });
    return;
  }
  if (loadError) {
    sendMsg({ type: "error", requestId, message: loadError });
    return;
  }
  if (loading) {
    // Wait for existing load
    while (loading) await new Promise(r => setTimeout(r, 100));
    if (pyodide) sendMsg({ type: "ready", requestId });
    else sendMsg({ type: "error", requestId, message: loadError || "Unknown load error" });
    return;
  }

  loading = true;

  try {
    const PYODIDE_MJS = "https://cdn.jsdelivr.net/pyodide/v314.0.2/full/pyodide.mjs";
    const mod = await import(PYODIDE_MJS);
    pyodide = await mod.loadPyodide({
      indexURL: "https://cdn.jsdelivr.net/pyodide/v314.0.2/full/",
    });
    loading = false;
    sendMsg({ type: "ready", requestId });
  } catch (err) {
    loading = false;
    loadError = String(err.message || err);
    sendMsg({ type: "error", requestId, message: loadError });
  }
}

// \u2500\u2500\u2500 Sync Files to MEMFS \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500
function syncFilesToMemfs(files) {
  if (!pyodide) return;
  const FS = pyodide.FS;
  for (const [path, content] of Object.entries(files)) {
    ensureParentDirs(FS, path);
    FS.writeFile(path, content, { encoding: "utf8" });
  }
}

// \u2500\u2500\u2500 Sync Files from MEMFS \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500
function syncFilesFromMemfs(knownPaths) {
  if (!pyodide) return {};
  const FS = pyodide.FS;
  const changed = {};

  // Check known paths
  for (const path of knownPaths) {
    try {
      const content = FS.readFile(path, { encoding: "utf8" });
      if (typeof content === "string") {
        changed[path] = content;
      }
    } catch {}
  }

  // Discover new files
  try {
    const memfsFiles = walkMemfs(FS, "/");
    const knownSet = new Set(knownPaths);
    for (const filePath of memfsFiles) {
      if (!knownSet.has(filePath)) {
        try {
          const content = FS.readFile(filePath, { encoding: "utf8" });
          if (typeof content === "string") {
            changed[filePath] = content;
          }
        } catch {}
      }
    }
  } catch {}

  return changed;
}

// \u2500\u2500\u2500 Run Python \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500
async function runPython(requestId, code, vfsSnapshot, knownPaths) {
  if (!pyodide) {
    sendMsg({ type: "error", requestId, message: "Pyodide not initialized" });
    return;
  }

  // Sync VFS \u2192 MEMFS
  if (vfsSnapshot) {
    syncFilesToMemfs(vfsSnapshot);
  }

  const stdoutBuffer = [];
  const stderrBuffer = [];

  pyodide.setStdout({ batched: (text) => stdoutBuffer.push(text) });
  pyodide.setStderr({ batched: (text) => stderrBuffer.push(text) });
  pyodide.setStdin({ error: true });

  let exitCode = 0;

  try {
    await pyodide.runPythonAsync(code);
  } catch (err) {
    stderrBuffer.push(err instanceof Error ? err.message : String(err));
    exitCode = 1;
  }

  // Sync MEMFS \u2192 VFS
  const changedFiles = syncFilesFromMemfs(knownPaths || []);

  sendMsg({
    type: "result",
    requestId,
    stdout: stdoutBuffer.join("\\n"),
    stderr: stderrBuffer.join("\\n"),
    exitCode,
    changedFiles,
  });
}

// \u2500\u2500\u2500 Install Package \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500
async function installPackage(requestId, name) {
  if (!pyodide) {
    sendMsg({ type: "error", requestId, message: "Pyodide not initialized" });
    return;
  }

  try {
    await pyodide.loadPackage(name);
    sendMsg({ type: "result", requestId, message: "Success: Package '" + name + "' installed." });
  } catch (err) {
    // Fallback to micropip
    try {
      await pyodide.runPythonAsync(
        'import micropip\\nawait micropip.install("' + name + '")'
      );
      sendMsg({ type: "result", requestId, message: "Success: Package '" + name + "' installed via micropip." });
    } catch (err2) {
      sendMsg({
        type: "result",
        requestId,
        message: "Error: Failed to install '" + name + "': " + (err2.message || err2),
      });
    }
  }
}

// \u2500\u2500\u2500 Incremental Sync Files \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500
function handleSyncFiles(requestId, added, deleted) {
  if (!pyodide) {
    sendMsg({ type: "error", requestId, message: "Pyodide not initialized" });
    return;
  }
  const FS = pyodide.FS;
  let applied = 0;
  let errors = 0;

  if (added) {
    for (const [path, content] of Object.entries(added)) {
      try {
        ensureParentDirs(FS, path);
        FS.writeFile(path, content, { encoding: "utf8" });
        applied++;
      } catch (err) {
        errors++;
      }
    }
  }

  if (deleted) {
    for (const path of deleted) {
      try {
        FS.unlink(path);
        applied++;
      } catch (err) {
        errors++;
      }
    }
  }

  sendMsg({ type: "result", requestId, message: "Synced " + applied + " files (" + errors + " errors)" });
}

// \u2500\u2500\u2500 Message Handler \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500
self.onmessage = async (e) => {
  const msg = e.data;
  if (!msg || !msg.type) return;

  switch (msg.type) {
    case "init":
      await initPyodide(msg.requestId);
      break;
    case "runPython":
      await runPython(msg.requestId, msg.code, msg.vfsSnapshot, msg.knownPaths);
      break;
    case "installPackage":
      await installPackage(msg.requestId, msg.name);
      break;
    case "syncFiles":
      handleSyncFiles(msg.requestId, msg.added, msg.deleted);
      break;
    case "terminate":
      self.close();
      break;
    default:
      sendMsg({ type: "error", message: "Unknown message type: " + msg.type });
  }
};

